import SdkForHansTypescript from "@bruno-scalar-com-teammm/sdk-for-hans";

const client = new SdkForHansTypescript({
  bearer_auth: process.env["BEARER_AUTH"], // defaults to the BEARER_AUTH env var
});

async function main() {
  const result = await client.planets.listAllData({
    limit: 10,
    offset: 0,
  });

  console.log(result);
}

main();

